import { defineMutator, defineMutators } from '@rocicorp/zero';
import { z } from 'zod';

import { zql } from './schema.js';

// ----
// Exported Zod input schemas (reusable for form validation, etc.)
// Preserve exact nullable/optional semantics — see plan notes on null vs undefined.

export const receiptsUpdateSchema = z.object({
  id: z.number(),
  tax: z.number().optional(),
  tip: z.number().optional(),
  gratuity: z.number().optional(),
  tip_after_tax: z.boolean().optional(),
  image_visibility: z.enum(['public', 'owner_only']).optional(),
});

export const receiptsSoftDeleteSchema = z.object({ id: z.number() });

export const lineItemsUpdateSchema = z.object({
  id: z.string(),
  name: z.string().optional(),
  quantity: z.number().optional(),
  price_per_item: z.number().optional(),
  total_price: z.number().optional(),
});

export const lineItemsSoftDeleteSchema = z.object({
  id: z.string(),
});

export const lineItemsInsertSchema = z.object({
  id: z.string(),
  receipt_id: z.number(),
  name: z.string().optional(),
  quantity: z.number().optional(),
  price_per_item: z.number().optional(),
  total_price: z.number().optional(),
  created_at: z.number().optional(),
});

export const receiptUsersInsertSchema = z.object({
  id: z.string(), // ULID
  display_name: z.string(),
  created_at: z.number().optional(),
});

export const receiptUsersUpdateSchema = z.object({
  id: z.string(),
  user_id: z.number().nullish(), // null = unclaim, number = claim, undefined = no change
  display_name: z.string().optional(),
});

export const receiptUsersUpdatePaidStatusSchema = z.object({
  id: z.string(),
  paid_at: z.number().nullable(),
});

export const receiptUsersDeleteSchema = z.object({ id: z.string() }); // ULID

export const assignmentsInsertSchema = z.object({
  id: z.string(), // ULID
  receipt_user_id: z.string(), // ULID
  receipt_line_item_id: z.string(),
  created_at: z.number().optional(),
  share_percentage: z.number().min(0).max(100).nullable().optional(),
  locked: z.boolean().optional(),
});

export const assignmentsUpdateSchema = z.object({
  id: z.string(), // ULID
  share_percentage: z.number().min(0).max(100).nullable().optional(),
  locked: z.boolean().optional(),
});

export const assignmentsDeleteSchema = z.object({ id: z.string() }); // ULID

// ----

export const mutators = defineMutators({
  receipts: {
    update: defineMutator(receiptsUpdateSchema, async ({ tx, args }) => {
      await tx.mutate.user_receipts.update(args);
    }),
    softDelete: defineMutator(
      receiptsSoftDeleteSchema,
      async ({ tx, args }) => {
        await tx.mutate.user_receipts.update({
          id: args.id,
          deleted_at: Date.now(),
        });
      }
    ),
  },
  lineItems: {
    update: defineMutator(lineItemsUpdateSchema, async ({ tx, args }) => {
      await tx.mutate.receipt_line_items.update(args);
    }),
    softDelete: defineMutator(
      lineItemsSoftDeleteSchema,
      async ({ tx, args }) => {
        await tx.mutate.receipt_line_items.update({
          id: args.id,
          deleted_at: Date.now(),
        });
      }
    ),
    insert: defineMutator(lineItemsInsertSchema, async ({ tx, args }) => {
      await tx.mutate.receipt_line_items.insert({
        id: args.id,
        receipt_id: args.receipt_id,
        name: args.name,
        quantity: args.quantity ?? 1,
        price_per_item: args.price_per_item ?? 0,
        total_price: args.total_price ?? 0,
        created_at: args.created_at ?? Date.now(),
      });
    }),
  },
  receiptUsers: {
    insert: defineMutator(receiptUsersInsertSchema, async ({ tx, args }) => {
      await tx.mutate.receipt_users.insert({
        id: args.id,
        display_name: args.display_name,
        created_at: args.created_at ?? Date.now(),
      });
    }),
    update: defineMutator(
      receiptUsersUpdateSchema,
      async ({ tx, args, ctx }) => {
        // When user_id isn't being changed, allow the update as-is on both client and server
        if (args.user_id === undefined) {
          await tx.mutate.receipt_users.update(args);
          return;
        }

        if (tx.location === 'server') {
          if (!ctx.userID) {
            throw new Error('Authentication required to change claim');
          }

          // Resolve Clerk auth ID -> numeric user ID
          const [authenticatedUser] = await tx.run(
            zql.users.where('auth_user_id', ctx.userID)
          );
          if (!authenticatedUser) {
            throw new Error('Authenticated user not found');
          }

          // Validate args.user_id: must be null (unclaim) or match authenticated user
          if (args.user_id !== null && args.user_id !== authenticatedUser.id) {
            throw new Error('Cannot claim as a different user');
          }

          // Atomic conditional update: only update when row is unclaimed or already claimed by this user
          const isClaim = args.user_id !== null;
          const includeDisplayName = args.display_name !== undefined;
          let sql: string;
          let params: unknown[];
          if (isClaim) {
            if (includeDisplayName) {
              sql =
                'UPDATE receipt_users SET user_id = $1, display_name = $2 WHERE id = $3 AND (user_id IS NULL OR user_id = $1) RETURNING id';
              params = [authenticatedUser.id, args.display_name, args.id];
            } else {
              sql =
                'UPDATE receipt_users SET user_id = $1 WHERE id = $2 AND (user_id IS NULL OR user_id = $1) RETURNING id';
              params = [authenticatedUser.id, args.id];
            }
          } else {
            if (includeDisplayName) {
              sql =
                'UPDATE receipt_users SET user_id = NULL, display_name = $1 WHERE id = $2 AND user_id = $3 RETURNING id';
              params = [args.display_name, args.id, authenticatedUser.id];
            } else {
              sql =
                'UPDATE receipt_users SET user_id = NULL WHERE id = $1 AND user_id = $2 RETURNING id';
              params = [args.id, authenticatedUser.id];
            }
          }
          const updated = await tx.dbTransaction.query(sql, params);
          const rowCount = Array.isArray(updated) ? updated.length : 0;
          if (rowCount === 0) {
            throw new Error('Already claimed by another user');
          }

          // Apply the same change via Zero mutate so sync state is updated
          await tx.mutate.receipt_users.update({
            id: args.id,
            ...(args.display_name !== undefined && {
              display_name: args.display_name,
            }),
            user_id: args.user_id === null ? null : authenticatedUser.id,
          });
        } else {
          // Client-side optimistic update -- trust the args
          await tx.mutate.receipt_users.update(args);
        }
      }
    ),
    updatePaidStatus: defineMutator(
      receiptUsersUpdatePaidStatusSchema,
      async ({ tx, args }) => {
        await tx.mutate.receipt_users.update({
          id: args.id,
          paid_at: args.paid_at,
        });
      }
    ),
    delete: defineMutator(receiptUsersDeleteSchema, async ({ tx, args }) => {
      await tx.mutate.receipt_users.update({
        id: args.id,
        deleted_at: Date.now(),
      });
    }),
  },
  assignments: {
    insert: defineMutator(assignmentsInsertSchema, async ({ tx, args }) => {
      await tx.mutate.assignments.insert({
        id: args.id,
        receipt_user_id: args.receipt_user_id,
        receipt_line_item_id: args.receipt_line_item_id,
        created_at: args.created_at ?? Date.now(),
        ...(args.share_percentage !== undefined && {
          share_percentage: args.share_percentage,
        }),
        locked: args.locked ?? false,
      });
    }),
    update: defineMutator(assignmentsUpdateSchema, async ({ tx, args }) => {
      await tx.mutate.assignments.update({
        id: args.id,
        ...(args.share_percentage !== undefined && {
          share_percentage: args.share_percentage,
        }),
        ...(args.locked !== undefined && { locked: args.locked }),
      });
    }),
    delete: defineMutator(assignmentsDeleteSchema, async ({ tx, args }) => {
      await tx.mutate.assignments.update({
        id: args.id,
        deleted_at: Date.now(),
      });
    }),
  },
});

import Decimal from 'decimal.js';

/**
 * Minimal structural shape consumed by the rebalance planners.
 *
 * Decoupled from the richer `Assignment` model so this module stays a pure
 * utility with no dependency on receipt-collab types; any caller whose
 * records expose `id`, `sharePercentage`, and `locked` can pass them in.
 */
export type RebalanceAssignment = {
  id: string;
  sharePercentage: Decimal | null;
  locked: boolean;
};

/**
 * Update payload for a single sibling assignment, shaped for the Zero
 * mutator (`share_percentage` as a raw `number`, not a `Decimal`).
 *
 * `locked` is optional because the mutator performs a partial update —
 * include it only when the rebalance needs to flip the lock flag (e.g.
 * the all-locked escape hatch in `planRemoveRebalance`).
 */
export type SiblingShareUpdate = {
  id: string;
  share_percentage: number;
  locked?: boolean;
};

/**
 * Result of planning the share distribution when a new assignment is added.
 *
 * `warning: 'fully-locked'` indicates the newcomer cannot receive any share
 * because the locked siblings already consume the entire 100% budget or no
 * unlocked sibling is available to donate.
 */
export type AddRebalanceResult = {
  newcomerShare: number;
  newcomerLocked: boolean;
  siblingUpdates: SiblingShareUpdate[];
  warning: 'fully-locked' | null;
};

// Module-local Decimal constants mirror the convention used by
// `features/assignments/utils/split-percent.ts` so arithmetic reads cleanly.
const ZERO = new Decimal(0);
const ONE_HUNDRED = new Decimal(100);

/**
 * Returns `true` if any assignment in the list has a custom (non-null)
 * share percentage — i.e. the item is in "percent" split mode rather than
 * even-split.
 *
 * @param assignments - The active assignments on a single line item.
 * @returns `true` when at least one assignment carries a `sharePercentage`.
 *
 * @example
 *   itemHasCustomShares([]); // → false
 *
 * @example
 *   itemHasCustomShares([
 *     { id: 'a', sharePercentage: null,               locked: false },
 *     { id: 'b', sharePercentage: new Decimal(60),    locked: true  },
 *   ]);
 *   // → true
 */
export function itemHasCustomShares(
  assignments: readonly RebalanceAssignment[]
): boolean {
  return assignments.some((assignment) => assignment.sharePercentage != null);
}

/**
 * Plan the share redistribution that should accompany adding a new
 * assignment to a line item that already uses custom shares.
 *
 * The policy is:
 *   1. If no existing sibling has a custom share (even-split regime), do
 *      nothing — return `null` so the caller can create the new assignment
 *      with `share_percentage: null`.

/**
 * Plan the share redistribution that should accompany removing an
 * assignment from a line item using custom shares.
 *
 * The policy is:
 *   1. If the removed assignment had no custom share, or no sibling
 *      remains, return `null` — the item either wasn't in percent mode or
 *      there's nothing left to redistribute onto.
 *   2. If every remaining sibling is locked, redistribute evenly across
 *      all of them and explicitly unlock each one (`locked: false` in the
 *      update payload). The mutator performs partial updates, so the
 *      lock flag has to be written out — simply overwriting the share
 *      would leave the stale lock in place.
 *   3. Otherwise, unlocked siblings absorb the removed share
 *      proportionally (evenly when their current shares sum to zero).
 *
 * @param removed - The assignment being removed.
 * @param remainingActive - The sibling assignments remaining after removal
 *                           (already filtered to exclude the removed one
 *                           and any soft-deleted rows).
 * @returns An array of sibling updates, or `null` when no redistribution
 *          should happen.
 *
 * @example
 *   // Removed had no custom share → no plan.
 *   planRemoveRebalance(
 *     { id: 'a', sharePercentage: null, locked: false },
 *     [{ id: 'b', sharePercentage: new Decimal(50), locked: false }],
 *   );
 *   // → null
 *
 * @example
 *   // Removing 30 with two unlocked siblings at 40 and 30 → they absorb proportionally.
 *   planRemoveRebalance(
 *     { id: 'a', sharePercentage: new Decimal(30), locked: false },
 *     [
 *       { id: 'b', sharePercentage: new Decimal(40), locked: false },
 *       { id: 'c', sharePercentage: new Decimal(30), locked: false },
 *     ],
 *   );
 *   // → [{ id: 'b', share_percentage: 40 + (40/70)*30 }, { id: 'c', share_percentage: 30 + (30/70)*30 }]
 *
 * @example
 *   // All remaining locked → even-split across all clears the locks implicitly.
 *   planRemoveRebalance(
 *     { id: 'a', sharePercentage: new Decimal(40), locked: false },
 *     [
 *       { id: 'b', sharePercentage: new Decimal(30), locked: true },
 *       { id: 'c', sharePercentage: new Decimal(30), locked: true },
 *     ],
 *   );
 *   // → [{ id: 'b', share_percentage: 50 }, { id: 'c', share_percentage: 50 }]
 */
export function planRemoveRebalance(
  removed: RebalanceAssignment,
  remainingActive: readonly RebalanceAssignment[]
): SiblingShareUpdate[] | null {
  // The removed row didn't contribute a custom share, so the item is in
  // even-split mode and no sibling needs adjusting.
  if (removed.sharePercentage == null) {
    return null;
  }

  // Nothing left to redistribute onto — the item will just be empty.
  if (remainingActive.length === 0) {
    return null;
  }

  // Lift everyone into Decimal space. When a sibling is in percent mode
  // but has no explicit share, fall back to the even-split value they
  // would have had; this mirrors the pre-refactor behavior.
  const removedShare = removed.sharePercentage;
  const evenFallback = ONE_HUNDRED.div(remainingActive.length);
  const siblings = remainingActive.map((assignment) => ({
    id: assignment.id,
    share: assignment.sharePercentage ?? evenFallback,
    locked: assignment.locked,
  }));

  // Partition into the unlocked pool (who will normally absorb the share)
  // and compute the sum we'll use for proportional scaling.
  const unlocked = siblings.filter((sibling) => !sibling.locked);
  const unlockedSum = unlocked.reduce(
    (accumulator, sibling) => accumulator.plus(sibling.share),
    ZERO
  );

  // Every remaining sibling is locked → no one can absorb the removed
  // share without breaking a lock. Overwrite everyone with an even split
  // and explicitly clear the lock flag; the mutator performs partial
  // updates, so omitting `locked` would leave the stale lock on the row.
  if (unlocked.length === 0) {
    const evenShare = ONE_HUNDRED.div(siblings.length);
    return siblings.map((sibling) => ({
      id: sibling.id,
      share_percentage: evenShare.toNumber(),
      locked: false,
    }));
  }

  // Normal path: grow each unlocked sibling's share by its proportional
  // slice of the removed share, or split evenly when the unlocked pool
  // sums to zero (to avoid a 0/0 ratio).
  return unlocked.map((sibling) => {
    if (unlockedSum.greaterThan(ZERO)) {
      // Proportional absorption: preserve each unlocked sibling's ratio.
      const nextShare = sibling.share.plus(
        sibling.share.div(unlockedSum).mul(removedShare)
      );
      return { id: sibling.id, share_percentage: nextShare.toNumber() };
    }

    // Degenerate: every unlocked sibling was already at zero, so split
    // the removed share evenly between them.
    const nextShare = sibling.share.plus(removedShare.div(unlocked.length));
    return { id: sibling.id, share_percentage: nextShare.toNumber() };
  });
}

